function solve(nums) {
    const N = nums.length;

    // 1. Find the Peak Index p (O(N))
    // p is the last index where nums is strictly increasing compared to the next element.
    let p = 0;
    while (p + 1 < N && nums[p] < nums[p + 1]) {
        p++;
    }

    // p is now the peak index.

    // 2. Calculate Increasing Sum (S_inc): indices 0 to p
    let s_inc = 0;
    for (let i = 0; i <= p; i++) {
        s_inc += nums[i];
    }

    // 3. Calculate Decreasing Sum (S_dec): indices p to N-1
    let s_dec = 0;
    for (let i = p; i < N; i++) {
        s_dec += nums[i];
    }

    // 4. Compare and Return
    if (s_inc > s_dec) {
        return 0; // Increasing sum is larger
    } else if (s_dec > s_inc) {
        return 1; // Decreasing sum is larger
    } else {
        return -1; // Sums are equal
    }
}

